#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define MAX_T 32
#define MAX_M 64

int main() {
    int T, r0, c0, i, j, M, r, c, dir;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &r0, &c0);
        M = 0;
        r = r0;
        c = c0;
        dir = 1;
        while (1) {
            printf("%d %d\n", r, c);
            M++;
            if (r < 1 || r > 888 || c < 1 || c > 888) break;
            if (r + c == r0 + c0) break;
            if (r + c < r0 + c0) {
                r++;
                c--;
            } else {
                r--;
                c++;
            }
        }
        printf("%d\n", M);
    }
    return 0;
}

